import{c as i,S as t,j as h,m as a}from"./chunks/framework.8aa1YH_s.js";const s=JSON.parse('{"title":"Mã khuyến mãi","description":"","frontmatter":{},"headers":[],"relativePath":"admin/khuyen-mai.md","filePath":"admin/khuyen-mai.md","lastUpdated":0}'),o={name:"admin/khuyen-mai.md"};function g(l,n,r,c,e,d){return t(),h("div",null,[...n[0]||(n[0]=[a('<h1 id="ma-khuyen-mai" tabindex="-1">Mã khuyến mãi <a class="header-anchor" href="#ma-khuyen-mai" aria-label="Permalink to “Mã khuyến mãi”">​</a></h1><p><strong>Đường dẫn:</strong> <code>https://lamsonedutech.vn/admin/business/discount</code></p><p>Tạo và quản lý <strong>mã giảm giá</strong> mà học viên có thể nhập khi thanh toán.</p><h2 id="danh-sach-ma" tabindex="-1">Danh sách mã <a class="header-anchor" href="#danh-sach-ma" aria-label="Permalink to “Danh sách mã”">​</a></h2><p>Cột chính:</p><ul><li>Mã khuyến mãi (vd <code>HSA2026</code>, <code>WELCOME50K</code>)</li><li>Loại giảm: <strong>% phần trăm</strong> hoặc <strong>số tiền cố định</strong></li><li>Giá trị giảm</li><li>Áp dụng cho: Tất cả khóa / Khóa cụ thể / Khung chương trình cụ thể</li><li>Điều kiện áp dụng: đơn tối thiểu, lần sử dụng</li><li>Ngày bắt đầu - Ngày kết thúc</li><li>Số lượng tổng / Đã dùng</li><li>Trạng thái (Đang chạy / Hết hạn / Tạm tắt)</li></ul><h2 id="tao-ma-khuyen-mai" tabindex="-1">Tạo mã khuyến mãi <a class="header-anchor" href="#tao-ma-khuyen-mai" aria-label="Permalink to “Tạo mã khuyến mãi”">​</a></h2><ol><li>Bấm <strong>Thêm mã</strong>.</li><li>Nhập <strong>Mã</strong>: nên ngắn, dễ nhớ, không dấu, không khoảng trắng.</li><li>Chọn <strong>Loại giảm</strong>: <ul><li><strong>% phần trăm</strong>: vd 10% (nên đặt mức tối đa giảm).</li><li><strong>Số tiền cố định</strong>: vd 50.000đ.</li></ul></li><li>Nhập <strong>Giá trị giảm</strong>.</li><li><strong>Phạm vi áp dụng</strong>: <ul><li>Tất cả khóa, hoặc</li><li>Chọn khóa / khung chương trình cụ thể.</li></ul></li><li><strong>Điều kiện</strong>: <ul><li>Đơn tối thiểu (vd: chỉ giảm khi mua ≥ 500.000đ).</li><li>Số lần sử dụng tối đa: tổng số người dùng và mỗi học viên dùng được mấy lần.</li><li>Áp dụng cho học viên mới / mọi học viên.</li></ul></li><li><strong>Thời gian hiệu lực</strong>: ngày bắt đầu - ngày kết thúc.</li><li><strong>Trạng thái</strong>: Bật / Tắt.</li><li>Bấm <strong>Lưu</strong>.</li></ol><h2 id="tam-tat-bat-lai-ma" tabindex="-1">Tạm tắt / Bật lại mã <a class="header-anchor" href="#tam-tat-bat-lai-ma" aria-label="Permalink to “Tạm tắt / Bật lại mã”">​</a></h2><ul><li>Cần tạm dừng phát hành mà không xóa: bấm <strong>Tắt</strong>.</li><li>Sau này mở lại: bấm <strong>Bật</strong>.</li></ul><h2 id="sua-ma" tabindex="-1">Sửa mã <a class="header-anchor" href="#sua-ma" aria-label="Permalink to “Sửa mã”">​</a></h2><ul><li>Có thể chỉnh giá trị giảm, thời gian, phạm vi.</li><li>Học viên đã sử dụng vẫn giữ giảm giá cũ trên hóa đơn của họ.</li></ul><h2 id="xoa-ma" tabindex="-1">Xóa mã <a class="header-anchor" href="#xoa-ma" aria-label="Permalink to “Xóa mã”">​</a></h2><ul><li>Chỉ xóa được mã <strong>chưa có ai sử dụng</strong>. Nếu đã có lượt dùng, hãy tắt thay vì xóa.</li></ul><h2 id="cach-hoc-vien-su-dung" tabindex="-1">Cách học viên sử dụng <a class="header-anchor" href="#cach-hoc-vien-su-dung" aria-label="Permalink to “Cách học viên sử dụng”">​</a></h2><ol><li>Học viên thêm khóa vào giỏ.</li><li>Tại trang <strong>Thanh toán</strong> → nhập <strong>Mã khuyến mãi</strong> vào ô tương ứng → bấm <strong>Áp dụng</strong>.</li><li>Hệ thống tự kiểm tra điều kiện và cập nhật giá.</li></ol><h2 id="theo-doi-hieu-qua" tabindex="-1">Theo dõi hiệu quả <a class="header-anchor" href="#theo-doi-hieu-qua" aria-label="Permalink to “Theo dõi hiệu quả”">​</a></h2><ul><li>Cột <strong>Đã dùng</strong> cho biết số lượt áp dụng thành công.</li><li>Xem <a href="./thong-ke#_1-thong-ke-khoa-hoc">Thống kê → Khóa học</a> để xem doanh thu theo khoảng thời gian, so trước/sau khi tung mã.</li></ul><h2 id="goi-y-chien-dich" tabindex="-1">Gợi ý chiến dịch <a class="header-anchor" href="#goi-y-chien-dich" aria-label="Permalink to “Gợi ý chiến dịch”">​</a></h2><table tabindex="0"><thead><tr><th>Loại chiến dịch</th><th>Mẫu mã</th></tr></thead><tbody><tr><td>Học viên mới</td><td><code>WELCOME50K</code>, giảm 50k cho đơn đầu, hết hạn 7 ngày</td></tr><tr><td>Đầu năm học</td><td><code>DAUNAM10</code>, giảm 10% cho mọi khóa, kéo dài 2 tuần</td></tr><tr><td>Sự kiện ngày 20/11</td><td><code>2011GV</code>, áp dụng cho khóa luyện thi</td></tr><tr><td>Black Friday</td><td><code>BF2025</code>, giảm 30%, giới hạn 100 lượt đầu</td></tr></tbody></table><h2 id="cau-hoi-thuong-gap" tabindex="-1">Câu hỏi thường gặp <a class="header-anchor" href="#cau-hoi-thuong-gap" aria-label="Permalink to “Câu hỏi thường gặp”">​</a></h2><p><strong>Học viên báo &quot;nhập mã nhưng không giảm giá&quot;.</strong> → Kiểm tra: mã còn hiệu lực? Đúng phạm vi khóa? Đơn của họ có đạt mức tối thiểu? Họ đã dùng mã này trước đó chưa?</p><p><strong>Có thể dùng 2 mã trong 1 đơn không?</strong> → Mặc định <strong>không</strong>. Nếu cần, hãy tạo 1 mã với mức giảm tương đương.</p><p><strong>Học viên muốn dùng mã sau khi đã thanh toán.</strong> → Hệ thống không hoàn lại tự động. Có thể hỗ trợ bằng cách gia hạn thêm hoặc tặng coupon mới.</p>',24)])])}const u=i(o,[["render",g]]);export{s as __pageData,u as default};
